What is the output of the following code?

```cpp
class Trace {
public:
    Trace() { cout << "A"; }
    Trace(int x) { cout << "B"; }
};

int main() {
    Trace t1;
    Trace t2(10);
    return 0;
}
```

Consider the following class. What will happen if you compile this code?

```cpp
class Sample {
    int x;
public:
    void setX(int a) { x = a; }
};

int main() {
    Sample s;
    s.x = 10;
    return 0;
}
```

What is the output of the following code?

```cpp
class Counter {
public:
    static int count;
    Counter() { count++; }
};

int Counter::count = 0;

int main() {
    Counter c1;
    Counter c2;
    Counter c3;
    cout << Counter::count;
    return 0;
}
```

What is the output of the following code?

```cpp
class MyClass {
    int val;
public:
    MyClass(int v) : val(v) {}
    int getVal() const { return val; }
};

int main() {
    MyClass obj1(5);
    MyClass obj2 = obj1;
    cout << obj2.getVal();
    return 0;
}
```

What is the output of the following code sequence?

```cpp
class Test {
public:
    ~Test() { cout << "D"; }
};

int main() {
    {
        Test t;
    }
    cout << "M";
    return 0;
}
```

What is the output of the following code snippet?

```cpp
class Point {
    int x, y;
public:
    Point() { x = 0; y = 0; }
    Point(int a, int b) { x = a; y = b; }
    void display() { cout << x << y; }
};

int main() {
    Point p[2] = {Point(1, 2)};
    p[0].display();
    p[1].display();
    return 0;
}
```

