What is the output of the following code?

```cpp
class Secret {
    int k;
public:
    Secret(int i) : k(i) {}
    void inc(int n) { k += n; }
    void print() { cout << k; }
};

void manipulate(Secret s) {
    s.inc(10);
}

int main() {
    Secret myS(5);
    manipulate(myS);
    myS.print();
    return 0;
}
```

What is the output of the following code?

```cpp
class Value {
public:
    int v;
    Value() { v = 1; }
    Value(int n) { v = n; }
};

int main() {
    Value v1(10);
    Value v2;
    v2 = v1;
    v1.v = 20;
    cout << v2.v;
    return 0;
}
```

Identify the result of this code:

```cpp
class Demo {
public:
    void func() { cout << "F"; }
};

int main() {
    Demo d();
    d.func();
    return 0;
}
```

What is the output of the following code?

```cpp
class Math {
public:
    static int calc(int x) { return x * 2; }
};

int main() {
    cout << Math::calc(5);
    return 0;
}
```

What is the output of the following code?

```cpp
class Box {
    int s;
public:
    Box(int side) { s = side; }
    int getArea() { return s * s; }
};

int main() {
    Box b1(4);
    Box b2(b1);
    cout << b2.getArea();
    return 0;
}
```

Consider the following class. Which line causes a compiler error?

```cpp
class ConstTest {
    int val;
public:
    ConstTest(int v) { val = v; } // Line 1
    void setVal(int v) const { val = v; } // Line 2
    int getVal() const { return val; } // Line 3
};
```

What is the output of the following code?

```cpp
class Data {
    int x;
public:
    Data(int a = 10) { x = a; }
    void print() { cout << x; }
};

int main() {
    Data d1;
    Data d2(5);
    d1.print();
    d2.print();
    return 0;
}
```

What is printed by the following code?

```cpp
class A {
public:
    A() { cout << "1"; }
    ~A() { cout << "2"; }
};

void f() {
    A obj;
}

int main() {
    f();
    cout << "3";
    return 0;
}
```
